"use strict";(self.webpackChunkhalt_website=self.webpackChunkhalt_website||[]).push([[54788],{8973:e=>{e.exports=JSON.parse('{"tag":{"label":"GI","permalink":"/docs/tags/gi","allTagsPath":"/docs/tags","count":1,"items":[{"id":"guinea-pigs/illnesses-and-conditions/bloat-in-guinea-pigs","title":"Bloat in Guinea Pigs","description":"Bloat, also known as Gastric Dilatation and Volvulus (GDV), is a sudden, life-threatening condition that can affect guinea pigs. It occurs when the stomach fills with gas and, in some cases, twists on itself (volvulus), cutting off blood supply to the stomach and other organs. This is a severe medical emergency that requires immediate veterinary intervention. Understanding the signs and acting quickly can be the difference between life and death.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/bloat-in-guinea-pigs"}],"unlisted":false}}')}}]);